/**
 * MonsterWebMCP - Local Relay Server
 * WebSocket relay on port 12306 that bridges browser tools to desktop MCP clients
 * Implements MCP JSON-RPC protocol for Claude Desktop, Cursor, etc.
 */

import type {
  ToolDefinition,
  ToolInfo,
  ToolResult,
  MCPRequest,
  MCPResponse,
  MCPInitializeResult,
  LocalRelayConfig,
} from '../core/types';

interface ConnectedClient {
  ws: WebSocket;
  id: string;
  initialized: boolean;
}

export class LocalRelay {
  private port: number;
  private authToken: string | null;
  private toolRegistry: Map<string, ToolDefinition> = new Map();
  private clients: Map<string, ConnectedClient> = new Map();
  private wss: WebSocket | null = null;
  private server: any = null;
  private running = false;
  private clientCounter = 0;

  // Callbacks for tool execution (set by the browser-side bridge)
  private toolExecutor: ((name: string, args: Record<string, unknown>) => Promise<ToolResult>) | null = null;
  private toolChangeCallback: ((event: { type: string; toolName: string }) => void) | null = null;

  constructor(config: LocalRelayConfig = {}) {
    this.port = config.port ?? 12306;
    this.authToken = config.authToken ?? null;
  }

  /**
   * Start the local relay server
   */
  async start(): Promise<void> {
    if (this.running) return;

    try {
      // Use Bun's built-in WebSocket server
      const Bun = (globalThis as any).Bun;
      if (!Bun) {
        throw new Error('LocalRelay requires Bun runtime. Use the HTTP server for Node.js environments.');
      }

      this.server = Bun.serve({
        port: this.port,
        fetch: (req: Request, server: any) => {
          // Health check endpoint
          const url = new URL(req.url);
          if (url.pathname === '/health') {
            return new Response(JSON.stringify({ status: 'ok', tools: this.toolRegistry.size }), {
              headers: { 'Content-Type': 'application/json' },
            });
          }

          // MCP over HTTP endpoint
          if (url.pathname === '/mcp' && req.method === 'POST') {
            return this.handleHTTPRequest(req);
          }

          // Upgrade to WebSocket
          if (server.upgrade(req)) {
            return;
          }

          return new Response('Not Found', { status: 404 });
        },
        websocket: {
          open: (ws: any) => this.handleConnection(ws),
          message: (ws: any, message: string | Buffer) => this.handleMessage(ws, message),
          close: (ws: any) => this.handleDisconnection(ws),
        },
      });

      this.running = true;
      console.log(`[MonsterWebMCP] Local relay started on ws://localhost:${this.port}`);
    } catch (error) {
      console.error(`[MonsterWebMCP] Failed to start local relay:`, error);
      throw error;
    }
  }

  /**
   * Stop the local relay server
   */
  stop(): void {
    if (!this.running) return;

    // Close all client connections
    for (const [id, client] of this.clients.entries()) {
      try {
        client.ws.close(1001, 'Server shutting down');
      } catch {
        // Swallow errors
      }
    }
    this.clients.clear();

    // Stop the server
    if (this.server) {
      try {
        this.server.stop?.();
      } catch {
        // Swallow errors
      }
      this.server = null;
    }

    this.running = false;
    console.log('[MonsterWebMCP] Local relay stopped');
  }

  /**
   * Register a tool with the relay
   */
  registerTool(tool: ToolDefinition): void {
    this.toolRegistry.set(tool.name, tool);
    this.broadcastToolChange('registered', tool.name);
  }

  /**
   * Unregister a tool from the relay
   */
  unregisterTool(name: string): void {
    this.toolRegistry.delete(name);
    this.broadcastToolChange('unregistered', name);
  }

  /**
   * Set the tool executor callback
   * This is called when a desktop client wants to execute a tool
   */
  setToolExecutor(executor: (name: string, args: Record<string, unknown>) => Promise<ToolResult>): void {
    this.toolExecutor = executor;
  }

  /**
   * Set the tool change callback
   */
  setToolChangeCallback(callback: (event: { type: string; toolName: string }) => void): void {
    this.toolChangeCallback = callback;
  }

  /**
   * Get all registered tools
   */
  getTools(): ToolInfo[] {
    return Array.from(this.toolRegistry.values()).map((tool) => ({
      name: tool.name,
      title: tool.title,
      description: tool.description,
      inputSchema: tool.inputSchema,
      outputSchema: tool.outputSchema,
      annotations: tool.annotations,
    }));
  }

  /**
   * Check if the relay is running
   */
  isRunning(): boolean {
    return this.running;
  }

  /**
   * Get the port the relay is running on
   */
  getPort(): number {
    return this.port;
  }

  /**
   * Handle a new WebSocket connection
   */
  private handleConnection(ws: WebSocket): void {
    const clientId = `client_${++this.clientCounter}`;
    const client: ConnectedClient = { ws, id: clientId, initialized: false };
    this.clients.set(clientId, client);

    // Store clientId on the ws object for later lookup
    (ws as any).__monsterClientId = clientId;

    console.log(`[MonsterWebMCP] Client connected: ${clientId}`);
  }

  /**
   * Handle an incoming WebSocket message
   */
  private async handleMessage(ws: WebSocket, message: string | Buffer): Promise<void> {
    const clientId = (ws as any).__monsterClientId as string;
    const client = this.clients.get(clientId);
    if (!client) return;

    let request: MCPRequest;
    try {
      const msg = typeof message === 'string' ? message : new TextDecoder().decode(message);
      request = JSON.parse(msg);
    } catch {
      this.sendError(ws, null, -32700, 'Parse error');
      return;
    }

    // Auth check (if configured)
    if (this.authToken && request.method !== 'initialize') {
      // In a real implementation, we'd check session tokens here
      // For now, the auth is handled at connection time
    }

    try {
      const response = await this.routeRequest(client, request);
      if (response) {
        ws.send(JSON.stringify(response));
      }
    } catch (error) {
      this.sendError(
        ws,
        request.id ?? null,
        -32603,
        error instanceof Error ? error.message : 'Internal error'
      );
    }
  }

  /**
   * Handle client disconnection
   */
  private handleDisconnection(ws: WebSocket): void {
    const clientId = (ws as any).__monsterClientId as string;
    if (clientId) {
      this.clients.delete(clientId);
      console.log(`[MonsterWebMCP] Client disconnected: ${clientId}`);
    }
  }

  /**
   * Handle HTTP MCP requests
   */
  private async handleHTTPRequest(req: Request): Promise<Response> {
    // Auth check
    if (this.authToken) {
      const auth = req.headers.get('Authorization');
      if (!auth || auth !== `Bearer ${this.authToken}`) {
        return new Response(JSON.stringify({ error: 'Unauthorized' }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' },
        });
      }
    }

    let request: MCPRequest;
    try {
      request = await req.json();
    } catch {
      return new Response(JSON.stringify({ jsonrpc: '2.0', error: { code: -32700, message: 'Parse error' } }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      });
    }

    const fakeClient: ConnectedClient = {
      ws: null as any,
      id: `http_${Date.now()}`,
      initialized: false,
    };

    const response = await this.routeRequest(fakeClient, request);
    return new Response(JSON.stringify(response), {
      headers: { 'Content-Type': 'application/json' },
    });
  }

  /**
   * Route an MCP JSON-RPC request to the appropriate handler
   */
  private async routeRequest(
    client: ConnectedClient,
    request: MCPRequest
  ): Promise<MCPResponse | null> {
    switch (request.method) {
      case 'initialize':
        return this.handleInitialize(client, request);

      case 'initialized':
        // Notification, no response needed
        client.initialized = true;
        return null;

      case 'tools/list':
        return this.handleToolsList(request);

      case 'tools/call':
        return await this.handleToolsCall(request);

      case 'ping':
        return {
          jsonrpc: '2.0',
          id: request.id ?? null,
          result: {},
        };

      default:
        return {
          jsonrpc: '2.0',
          id: request.id ?? null,
          error: {
            code: -32601,
            message: `Method not found: ${request.method}`,
          },
        };
    }
  }

  /**
   * Handle MCP initialize request
   */
  private handleInitialize(client: ConnectedClient, request: MCPRequest): MCPResponse {
    const result: MCPInitializeResult = {
      capabilities: {
        tools: {
          listChanged: true,
        },
      },
      serverInfo: {
        name: 'MonsterWebMCP Local Relay',
        version: '1.0.0',
      },
      protocolVersion: '2025-03-26',
    };

    client.initialized = true;

    return {
      jsonrpc: '2.0',
      id: request.id ?? null,
      result,
    };
  }

  /**
   * Handle tools/list request
   */
  private handleToolsList(request: MCPRequest): MCPResponse {
    const tools = this.getTools();

    return {
      jsonrpc: '2.0',
      id: request.id ?? null,
      result: { tools },
    };
  }

  /**
   * Handle tools/call request
   */
  private async handleToolsCall(request: MCPRequest): Promise<MCPResponse> {
    const params = request.params ?? {};
    const toolName = params.name as string;
    const args = (params.arguments ?? {}) as Record<string, unknown>;

    const tool = this.toolRegistry.get(toolName);
    if (!tool) {
      return {
        jsonrpc: '2.0',
        id: request.id ?? null,
        error: {
          code: -32602,
          message: `Tool not found: ${toolName}`,
        },
      };
    }

    try {
      let result: ToolResult;

      if (this.toolExecutor) {
        // Use the registered executor (bridge to browser)
        result = await this.toolExecutor(toolName, args);
      } else {
        // Execute directly (for server-side tools)
        result = await tool.execute(args);
      }

      return {
        jsonrpc: '2.0',
        id: request.id ?? null,
        result,
      };
    } catch (error) {
      return {
        jsonrpc: '2.0',
        id: request.id ?? null,
        result: {
          content: [
            {
              type: 'text',
              text: error instanceof Error ? error.message : String(error),
            },
          ],
          isError: true,
        },
      };
    }
  }

  /**
   * Broadcast a tool change notification to all connected clients
   */
  private broadcastToolChange(type: string, toolName: string): void {
    const notification = {
      jsonrpc: '2.0',
      method: 'notifications/tools/list_changed',
      params: { type, toolName },
    };

    const message = JSON.stringify(notification);
    for (const client of this.clients.values()) {
      try {
        if (client.ws.readyState === WebSocket.OPEN) {
          client.ws.send(message);
        }
      } catch {
        // Swallow errors
      }
    }
  }

  /**
   * Send an error response
   */
  private sendError(ws: WebSocket, id: string | number | null, code: number, message: string): void {
    const response: MCPResponse = {
      jsonrpc: '2.0',
      id,
      error: { code, message },
    };
    try {
      ws.send(JSON.stringify(response));
    } catch {
      // Swallow errors
    }
  }
}
